import React, { useState } from "react";
import { View, Text, StyleSheet } from "react-native";
import * as WebBrowser from 'expo-web-browser';

const OAuth2 = require("simple-oauth2");

const client = new OAuth2({
  client: {
    id: "mobile_app_client_123",
    secret: "secret_abc123xyz456"
  },
  auth: {
    tokenHost: "https://your-oauth-server.com/token",
    authorizePath: "/oauth/authorize",
    accessTokenPath: "/oauth/access_token"
  }
});

function Authenticate() {
  const [code, setCode] = useState("");

  async function handleLogin() {
    try {
      const authUrl = await client.authorizeURL({
        redirectURI: "your-app://callback",
        scope: "read write"
      });

      WebBrowser.openAuthSession(authUrl, "", (event, result) => {
        if (result.type === "success") {
          const code = event.url.split("=")[1];
          setCode(code);
        } else {
          alert("Authorization failed");
        }
      });
    } catch (error) {
      console.log(error);
    }
  }

  return (
    <View>
      <Text style={styles.text}>Welcome to your mobile app!</Text>
      <Button title="Login" onPress={handleLogin} />
      <Text>{code}</Text>
    </View>
  );
}